USE VACCINE ;DROP TABLE IF EXISTS 外来情報;CREATE TABLE 外来情報 (    APPOINTMENTNO VARCHAR(20) NOT NULL,          -- 予約番号    PATIENTNO VARCHAR(20) NOT NULL,              -- 患者番号    DEPARTMENTCODE VARCHAR(10),                  -- 部署コード    DEPARTMENTNAME VARCHAR(50),                  -- 部署名    SEX VARCHAR(1),                              -- 性別    PATIENTAGE INT,                              -- 患者年齢    VISITDATE DATE NULL,                         -- 受診日（日付のみ、NULL許容）    VISITTIME VARCHAR(10),                       -- 受診時刻（文字列として保持）    CONSULTSTARTTIME VARCHAR(10),                -- 診察開始時刻（文字列として保持）    CONSULTENDTIME VARCHAR(10),                  -- 診察終了時刻（文字列として保持）    ADMISSIONDEPT VARCHAR(10),                   -- 入院部署    ADMISSIONDEPTNAME VARCHAR(50),               -- 入院部署名    ADMISSIONWARD VARCHAR(10)                    -- 入院病棟    -- PRIMARY KEY (APPOINTMENTNO)                  -- 予約番号を主キーに設定);LOAD DATA INFILE '/Users/myamaguchi/Data/Vaccin/CH_t02_外来情報_納品.txt'INTO TABLE 外来情報CHARACTER SET sjisFIELDS TERMINATED BY ','ENCLOSED BY '"'LINES TERMINATED BY '\r\n'IGNORE 1 ROWS(    APPOINTMENTNO,    PATIENTNO,    DEPARTMENTCODE,    DEPARTMENTNAME,    SEX,    PATIENTAGE,    @VISITDATE_STR,     -- 一時変数に読み込む    VISITTIME,    CONSULTSTARTTIME,    CONSULTENDTIME,    ADMISSIONDEPT,    ADMISSIONDEPTNAME,    ADMISSIONWARD)SET    -- VISITDATEカラムの処理:    -- NULLIF(@VISITDATE_STR, '') は、@VISITDATE_STRが空文字列の場合にNULLを返し、    -- それ以外の場合（空ではない文字列）は@VISITDATE_STRをそのまま返します。    -- STR_TO_DATE(NULL, ...) はNULLを返すため、結果的に空文字列はDATE型NULLとして格納されます。    VISITDATE = STR_TO_DATE(NULLIF(@VISITDATE_STR, ''), '%Y/%m/%d %H:%i:%s');select * from 外来情報 limit 10;